"""Workflow-first built-in web GUI for tb2 MCP control."""
from __future__ import annotations
GUI_HTML_TEMPLATE = r"""<!doctype html><html lang=en><head><meta charset=utf-8><meta name=viewport content='width=device-width,initial-scale=1'><title>tb2 Orchestrator</title><style>body{margin:0;font-family:"Segoe UI",sans-serif;background:linear-gradient(180deg,#fbfdff,#e8f0ff);color:#173056}main{width:min(1180px,96vw);margin:20px auto;display:grid;gap:12px}.hero,.card{background:#fff;border:1px solid #c8d8ef;border-radius:16px;box-shadow:0 12px 32px rgba(18,50,96,.12)}.hero,.card{padding:16px}.hero small{display:block;color:#1158b4;text-transform:uppercase;letter-spacing:.06em;margin-bottom:6px}.grid{display:grid;grid-template-columns:repeat(12,minmax(0,1fr));gap:12px}.c5{grid-column:span 5}.c7{grid-column:span 7}.c12{grid-column:span 12}@media(max-width:980px){.c5,.c7,.c12{grid-column:span 12}}.row{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px;margin:0 0 10px}.row.one{grid-template-columns:1fr}.row.three{grid-template-columns:repeat(3,minmax(0,1fr))}@media(max-width:720px){.row,.row.three{grid-template-columns:1fr}}label{display:block;font-size:.78rem;color:#5b7496;margin-bottom:4px}input,select,textarea,pre{width:100%;box-sizing:border-box;border:1px solid #c8d8ef;border-radius:12px;background:#f5f9ff;color:#173056;padding:9px 10px;font:inherit}textarea,pre{font-family:Consolas,monospace;font-size:.83rem;line-height:1.38}textarea{min-height:90px;resize:vertical}pre{white-space:pre-wrap;overflow:auto;max-height:280px}button{border:0;border-radius:12px;padding:9px 13px;font-weight:600;cursor:pointer;color:#fff;background:#1158b4}button.alt{background:#116c7b}button.ok{background:#198b5e}button.warn{background:#cb5c2f}button.ghost{background:#dce9ff;color:#114586}.actions,.meta,.checks{display:flex;flex-wrap:wrap;gap:8px;align-items:center;margin-top:8px}.checks{color:#5b7496;font-size:.86rem}.checks input{width:auto;margin-right:6px}.badge{display:inline-flex;padding:5px 12px;border-radius:999px;background:#dce9ff;color:#114586;border:1px solid #b6cbef;font-size:.82rem}.stats{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px;margin-bottom:12px}@media(max-width:900px){.stats{grid-template-columns:repeat(2,minmax(0,1fr))}}.stat,.pending-item{border:1px solid #c8d8ef;border-radius:14px;background:#f5f9ff;padding:10px}.stat b{display:block;color:#5b7496;font-size:.76rem;text-transform:uppercase;letter-spacing:.05em;margin-bottom:6px}.pending-item.active{outline:2px solid #cb5c2f}details{margin-top:10px;border-top:1px dashed #c8d8ef;padding-top:10px}summary{cursor:pointer;color:#1158b4;font-weight:600}</style></head><body><main><section class=hero><small>AI-first orchestration cockpit</small><h1>Host, Guest, and Human operator workflow</h1><p>Launch the session, start collaboration, watch the live room over SSE/WebSocket/poll, and step in only when intervention is needed.</p><div class=meta><span class=badge>MCP __MCP_ENDPOINT__</span><span class=badge id=transport-badge>transport idle</span></div></section><section class=grid><article class='card c5'><h2>Launch Session</h2><p>Default flow stays high-level. Raw ids and panes live in Advanced.</p><div class=row><div><label for=backend>backend</label><select id=backend><option value=process>process</option><option value=tmux>tmux</option><option value=pipe>pipe</option></select></div><div><label for=profile>profile</label><select id=profile><option value=generic>generic</option><option value=codex>codex</option><option value=claude-code>claude-code</option><option value=aider>aider</option><option value=llama>llama</option><option value=gemini>gemini</option></select></div></div><div class=row><div><label for=session>session</label><input id=session value=tb2-ai-first></div><div><label for=transport>live room transport</label><select id=transport><option value=sse>SSE</option><option value=ws>WebSocket</option><option value=poll>room_poll</option></select></div></div><div class=checks><label><input id=auto-forward type=checkbox checked>auto-forward Guest MSG handoffs</label><label><input id=intervention type=checkbox>human operator approval gate</label></div><div class=actions><button id=init-session>Init Session</button><button id=start-bridge class=alt>Start Collaboration</button><button id=stop-bridge class=warn>Stop Bridge</button><button id=refresh-status class=ghost>Refresh Status</button></div><details><summary>Advanced identifiers and pane mapping</summary><div class=row><div><label for=backend-id>backend_id</label><input id=backend-id value=default></div><div><label for=bridge-id>bridge_id</label><input id=bridge-id placeholder='auto if empty'></div></div><div class=row><div><label for=room-id>room_id</label><input id=room-id placeholder='auto if empty'></div><div><label for=deliver>human delivery target</label><select id=deliver><option value=''>room only</option><option value=a>Host pane</option><option value=b>Guest pane</option><option value=both>Both panes</option></select></div></div><div class=row><div><label for=pane-a>Host pane</label><input id=pane-a placeholder='filled by Init Session'></div><div><label for=pane-b>Guest pane</label><input id=pane-b placeholder='filled by Init Session'></div></div></details><pre id=status-box></pre></article><article class='card c7'><h2>Run Collaboration</h2><div class=stats><div class=stat><b>Host</b><div id=metric-host>not ready</div></div><div class=stat><b>Guest</b><div id=metric-guest>not ready</div></div><div class=stat><b>Room</b><div id=metric-room>not attached</div></div><div class=stat><b>Bridge</b><div id=metric-bridge>not running</div></div></div><div class='row one'><div><label for=send-text>human operator message</label><textarea id=send-text placeholder='Short instruction for Host, Guest, or room'></textarea></div></div><div class=actions><button id=send-host>Send to Host</button><button id=send-guest>Send to Guest</button><button id=send-room class=ghost>Post to Room</button><button id=capture-host class=ghost>Capture Host</button><button id=capture-guest class=ghost>Capture Guest</button></div><div class=row><div><label for=capture-a-box>Host capture</label><textarea id=capture-a-box readonly></textarea></div><div><label for=capture-b-box>Guest capture</label><textarea id=capture-b-box readonly></textarea></div></div></article><article class='card c5'><h2>Human Control</h2><div class=actions><button id=refresh-pending class=ghost>Refresh Pending</button><button id=approve-all class=ok>Approve All</button><button id=reject-all class=warn>Reject All</button></div><div class='row one'><div><label for=pending-select>pending intervention items</label><select id=pending-select size=8></select></div></div><div class='row one'><div><label for=pending-edit>edited approval text</label><textarea id=pending-edit placeholder='Optional replacement text for selected item'></textarea></div></div><div class=actions><button id=approve-selected class=ok>Approve Selected</button><button id=reject-selected class=warn>Reject Selected</button></div><div class=actions><button id=interrupt-host class=warn>Interrupt Host</button><button id=interrupt-guest class=warn>Interrupt Guest</button><button id=interrupt-both class=warn>Interrupt Both</button></div></article><article class='card c7'><h2>Live Room</h2><p>SSE is the default path. Switch to WebSocket or `room_poll` for parity and debugging.</p><pre id=stream-box></pre></article><article class='card c12'><h2>Activity Log</h2><pre id=log-box></pre></article></section><script>const MCP_ENDPOINT="__MCP_ENDPOINT__";const SERVER_ROOT=new URL(MCP_ENDPOINT,window.location.href).origin;const state={reqId:1,lastMsgId:0,poller:null,sse:null,ws:null,seen:new Set()};const $=id=>document.getElementById(id);const log=t=>{const b=$("log-box");b.textContent+="["+new Date().toLocaleTimeString()+"] "+t+"\n";b.scrollTop=b.scrollHeight};const commonArgs=()=>({backend:$("backend").value.trim(),backend_id:$("backend-id").value.trim()||"default"});const normalize=r=>{if(!r||typeof r!=="object")return r;if(r.structuredContent&&typeof r.structuredContent==="object")return r.structuredContent;if(!Array.isArray(r.content))return r;const item=r.content.find(x=>x&&x.type==="text"&&typeof x.text==="string");if(!item)return{};try{return JSON.parse(item.text)}catch(_){return{text:item.text}}};async function rpc(method,params){const res=await fetch(MCP_ENDPOINT,{method:"POST",headers:{"content-type":"application/json"},body:JSON.stringify({jsonrpc:"2.0",id:state.reqId++,method,params:params||{}})});const data=await res.json();if(data.error)throw new Error(data.error.message||JSON.stringify(data.error));return data.result}async function tool(name,args){const raw=await rpc("tools/call",{name,arguments:args||{}});const out=normalize(raw);if(raw&&raw.isError)throw new Error((out&&out.error)||"tool call failed");if(out&&typeof out.error==="string")throw new Error(out.error);return out}function syncMetrics(){$("metric-host").textContent=$("pane-a").value.trim()||"not ready";$("metric-guest").textContent=$("pane-b").value.trim()||"not ready";$("metric-room").textContent=$("room-id").value.trim()||"not attached";$("metric-bridge").textContent=$("bridge-id").value.trim()||"not running";$("transport-badge").textContent=$("transport").value+" active"}function appendEvent(ev){if(!ev)return;const key=ev.event_id||String(ev.id||"");if(key&&state.seen.has(key))return;if(key)state.seen.add(key);state.lastMsgId=Math.max(state.lastMsgId,Number(ev.id||0));const box=$("stream-box");box.textContent+="["+(ev.kind||"chat")+"] "+(ev.author||"?")+" | "+(ev.text||"")+"\n";box.scrollTop=box.scrollHeight}function stopTransport(){if(state.poller){clearInterval(state.poller);state.poller=null}if(state.sse){state.sse.close();state.sse=null}if(state.ws){state.ws.close();state.ws=null}}async function pollRoom(){const roomId=$("room-id").value.trim();if(!roomId)return;const res=await tool("room_poll",{room_id:roomId,after_id:state.lastMsgId,limit:200});for(const msg of(res.messages||[]))appendEvent(msg)}function connectTransport(){stopTransport();const roomId=$("room-id").value.trim();if(!roomId)return;const mode=$("transport").value;$("transport-badge").textContent=mode+" active";if(mode==="poll"){pollRoom();state.poller=setInterval(()=>run(pollRoom),1200);return}if(mode==="sse"){const es=new EventSource(SERVER_ROOT+"/rooms/"+encodeURIComponent(roomId)+"/stream?after_id="+encodeURIComponent(String(state.lastMsgId))+"&limit=200");state.sse=es;es.addEventListener("room",e=>appendEvent(JSON.parse(e.data)));es.addEventListener("ready",e=>log("SSE ready for room "+JSON.parse(e.data).room_id));es.onerror=()=>log("SSE stream disconnected");return}const wsUrl=new URL(SERVER_ROOT+"/ws",window.location.href);wsUrl.protocol=wsUrl.protocol==="https:"?"wss:":"ws:";const ws=new WebSocket(wsUrl.toString());state.ws=ws;ws.addEventListener("open",()=>ws.send(JSON.stringify({action:"subscribe",room_id:roomId,after_id:state.lastMsgId,limit:200})));ws.addEventListener("message",e=>{const msg=JSON.parse(e.data);if(msg.type==="room_event"&&msg.event)appendEvent(msg.event);else if(msg.type==="subscribed")log("WebSocket subscribed to room "+msg.room_id);else if(msg.type==="error")log("ws error: "+msg.error)});ws.addEventListener("close",()=>log("WebSocket stream closed"))}function fillPending(items){const sel=$("pending-select");sel.innerHTML="";for(const item of items||[]){const opt=document.createElement("option");opt.value=String(item.id);opt.textContent="#"+item.id+" "+item.from_pane+" -> "+item.to_pane+" | "+item.text;sel.appendChild(opt)}if(sel.options.length)sel.selectedIndex=0}async function refreshPending(){const bridgeId=$("bridge-id").value.trim();if(!bridgeId){fillPending([]);return}const res=await tool("intervention_list",{bridge_id:bridgeId});fillPending(res.pending||[]);return res}async function refreshStatus(){const res=await tool("status",{});$("status-box").textContent=JSON.stringify(res,null,2);syncMetrics();return res}async function initSession(){const res=await tool("terminal_init",Object.assign({session:$("session").value.trim()||"tb2-ai-first"},commonArgs()));$("pane-a").value=res.pane_a||"";$("pane-b").value=res.pane_b||"";syncMetrics();log("Host + Guest panes ready in session "+(res.session||""));return res}async function startBridge(){if(!$("pane-a").value.trim()||!$("pane-b").value.trim())throw new Error("pane targets are required");const args=Object.assign({pane_a:$("pane-a").value.trim(),pane_b:$("pane-b").value.trim(),profile:$("profile").value.trim()||"generic",auto_forward:$("auto-forward").checked,intervention:$("intervention").checked},commonArgs());if($("bridge-id").value.trim())args.bridge_id=$("bridge-id").value.trim();if($("room-id").value.trim())args.room_id=$("room-id").value.trim();const res=await tool("bridge_start",args);$("bridge-id").value=res.bridge_id||"";$("room-id").value=res.room_id||"";state.lastMsgId=0;state.seen=new Set();$("stream-box").textContent="";connectTransport();await refreshPending();await refreshStatus();log("Collaboration bridge online: "+(res.bridge_id||""));return res}async function stopBridge(){const bridgeId=$("bridge-id").value.trim();if(!bridgeId)throw new Error("bridge_id is required");const res=await tool("bridge_stop",{bridge_id:bridgeId});stopTransport();await refreshPending();await refreshStatus();log("Bridge stopped");return res}async function sendRoom(deliver){const roomId=$("room-id").value.trim();const text=$("send-text").value.trim();if(!roomId)throw new Error("room_id is required");if(!text)throw new Error("message is empty");const args={room_id:roomId,author:"human-operator",text};if(deliver){args.deliver=deliver;args.bridge_id=$("bridge-id").value.trim()}const res=await tool("room_post",args);$("send-text").value="";log("Human operator message posted"+(deliver?" to "+deliver:" to room"));return res}async function capture(targetId,outId){const target=$(targetId).value.trim();if(!target)throw new Error("target pane is required");const res=await tool("terminal_capture",Object.assign({target,lines:160},commonArgs()));$(outId).value=(res.lines||[]).join("\n");log("Captured "+target);return res}async function interrupt(target){const bridgeId=$("bridge-id").value.trim();if(!bridgeId)throw new Error("bridge_id is required");const res=await tool("terminal_interrupt",{bridge_id:bridgeId,target});log("Interrupt sent to "+target);return res}async function approveSelected(){const bridgeId=$("bridge-id").value.trim();const id=$("pending-select").value;if(!bridgeId||!id)throw new Error("select a pending item first");const args={bridge_id:bridgeId,id:Number(id)};const edited=$("pending-edit").value.trim();if(edited)args.edited_text=edited;const res=await tool("intervention_approve",args);await refreshPending();log("Pending handoff approved");return res}async function rejectSelected(){const bridgeId=$("bridge-id").value.trim();const id=$("pending-select").value;if(!bridgeId||!id)throw new Error("select a pending item first");const res=await tool("intervention_reject",{bridge_id:bridgeId,id:Number(id)});await refreshPending();log("Pending handoff rejected");return res}async function run(fn){try{return await fn()}catch(err){log("error: "+err.message)}}function bind(){$("init-session").onclick=()=>run(initSession);$("start-bridge").onclick=()=>run(startBridge);$("stop-bridge").onclick=()=>run(stopBridge);$("refresh-status").onclick=()=>run(refreshStatus);$("refresh-pending").onclick=()=>run(refreshPending);$("send-host").onclick=()=>run(()=>sendRoom("a"));$("send-guest").onclick=()=>run(()=>sendRoom("b"));$("send-room").onclick=()=>run(()=>sendRoom($("deliver").value||""));$("capture-host").onclick=()=>run(()=>capture("pane-a","capture-a-box"));$("capture-guest").onclick=()=>run(()=>capture("pane-b","capture-b-box"));$("interrupt-host").onclick=()=>run(()=>interrupt("a"));$("interrupt-guest").onclick=()=>run(()=>interrupt("b"));$("interrupt-both").onclick=()=>run(()=>interrupt("both"));$("approve-selected").onclick=()=>run(approveSelected);$("reject-selected").onclick=()=>run(rejectSelected);$("approve-all").onclick=()=>run(()=>tool("intervention_approve",{bridge_id:$("bridge-id").value.trim(),id:"all"}).then(refreshPending));$("reject-all").onclick=()=>run(()=>tool("intervention_reject",{bridge_id:$("bridge-id").value.trim(),id:"all"}).then(refreshPending));$("transport").onchange=()=>{syncMetrics();connectTransport()};$("pending-select").onchange=()=>{$("pending-edit").value=""}}async function boot(){bind();log("GUI ready, endpoint "+MCP_ENDPOINT);await run(async()=>{const profiles=await tool("list_profiles",{});if(!profiles||!Array.isArray(profiles.profiles))return;const select=$("profile");const known=new Set(Array.from(select.options).map(opt=>opt.value));for(const p of profiles.profiles){if(known.has(p))continue;const option=document.createElement("option");option.value=p;option.textContent=p;select.appendChild(option)}});await run(refreshStatus)}boot();</script></main></body></html>"""
def build_gui_html(mcp_endpoint: str = "/mcp") -> str:
    return GUI_HTML_TEMPLATE.replace("__MCP_ENDPOINT__", mcp_endpoint)
